import { SignatureFilled, ReadFilled, FileTextFilled, WechatFilled, FlagFilled, SunFilled, ToolFilled } from '@ant-design/icons';
import casey from '../img/casey.JPG';

export const AboutMeContainer = () => {
    return (
        <div>
            <p>This page is for getting to know me better. Here are some things I enjoy doing:</p>
            <div className='AboutMeContainer'>
                <ul style={{ listStyleType: 'none', padding: 0 }}>
                    <li><SignatureFilled /> &nbsp;Working with UX Design to solve problems</li>
                    <li><ReadFilled /> &nbsp;Reading all kinds of books</li>
                    <li><FileTextFilled /> &nbsp;Journaling</li>
                    <li><WechatFilled /> &nbsp;Get to know new people</li>
                    <li><FlagFilled /> &nbsp;Playing Videogames</li>
                    <li><SunFilled /> &nbsp;Taking a walk with my dog</li>
                    <li><ToolFilled /> &nbsp;Working on improving myself</li>
                </ul>
                <img
                    src={casey}
                    alt="My dog Casey"
                    width={100}
                    height='auto'
                />
            </div>
        </div>
    );
}
